if (await isTransparentProxy(provider, proxyAddress)) {
    importKind = 'transparent';
} else if (await isTransparentOrUUPSProxy(provider, proxyAddress)) {
    importKind = 'uups';
} else if (await isBeaconProxy(provider, proxyAddress)) {
    importKind = 'beacon';
} else {
    throw new ZkSyncUpgradablePluginError(`Contract at ${proxyAddress} doesn't look like an ERC 1967 proxy`);
}

for (const dependencyHash in artifact.factoryDeps) {
    if (!dependencyHash) continue;
    const dependencyContract = artifact.factoryDeps[dependencyHash];
    if (!visited.has(dependencyContract)) {
        const dependencyArtifact = await loadArtifact(hre, dependencyContract);
        factoryDeps.push(dependencyArtifact.bytecode);
        visited.add(dependencyContract);
        const transitiveDeps = await _extractFactoryDepsRecursive(hre, dependencyArtifact, visited);
        factoryDeps.push(...transitiveDeps);
    }
}

for (const dependencyHash in artifact.factoryDeps) {
    if (!dependencyHash) continue;
    const dependencyContract = artifact.factoryDeps[dependencyHash];
    if (!visited.has(dependencyContract)) {
        const dependencyArtifact = await loadArtifact(hre, dependencyContract);
        factoryDeps.push(dependencyArtifact.bytecode);
        visited.add(dependencyContract);
        const transitiveDeps = await extractFactoryDepsRecursive(hre, dependencyArtifact, visited);
        factoryDeps.push(...transitiveDeps);
