}

switch (config.compilerSource) {
    case 'binary':
        if (!solcPath) {
            throw new ZkSyncSolcPluginError('solc executable is not specified');
        }
        return new BinaryCompiler(solcPath);

    case 'docker':
        return DockerCompiler.initialize(config);

    default:
        throw new ZkSyncSolcPluginError(`Incorrect compiler source: ${config.compilerSource}`);
}

const createPermissionForContract = async (
  hre: HardhatRuntimeEnvironment,
  signer: SignerWithAddress,
  contractAddress: string,
): Promise<Permission> => {
  const provider = hre.ethers.provider;

  const permit = await hre.fhenixjs.generatePermit(
    contractAddress,
    provider,
    signer,
  );
  const permission = hre.fhenixjs.extractPermitPermission(permit);

  return permission;
};

